ValidationRule.errorConditionFormula:
AND(
    /* 1. 단계가 변경되었을 때만 작동 */
    ISCHANGED(StageName), 

    /* 2. '계약 생성 🤝' 단계로 가려고 할 때 (또는 마감 단계들) */
    OR(
        ISPICKVAL(StageName, "계약 생성"),
        ISPICKVAL(StageName, "마감됨") 
    ),

    /* 3. 동기화된 견적 필드가 비어있다면 에러! */
    ISBLANK(SyncedQuoteId)
)
